import Foundation

enum NetworkError: Error, LocalizedError {
    case invalidURL
    case noData
    case decodeFailed(Error)
    case apiError(String)
    case unauthorized
    case serverError(Int)
    case unknown

    var errorDescription: String? {
        switch self {
        case .invalidURL: return "The URL provided was invalid."
        case .noData: return "No data was received from the server."
        case .decodeFailed(let error): return "Failed to decode data: \(error.localizedDescription)"
        case .apiError(let message): return "API Error: \(message)"
        case .unauthorized: return "You are not authorized to perform this action."
        case .serverError(let statusCode): return "Server error with status code: \(statusCode)"
        case .unknown: return "An unknown error occurred."
        }
    }
}

enum HTTPMethod: String {
    case get = "GET"
    case post = "POST"
}

struct APIConfiguration {
    enum Environment {
        case development
        case staging
        case production
    }

    static var current: Environment = .development

    static var baseURL: URL {
        switch current {
        case .development: return URL(string: "https://api.example.com/dev")! // Replace with your dev URL
        case .staging: return URL(string: "https://api.example.com/staging")! // Replace with your staging URL
        case .production: return URL(string: "https://api.example.com")!
        }
    }
}

class NetworkService {
    static let shared = NetworkService()
    private let session: URLSession

    private init() {
        let config = URLSessionConfiguration.default
        config.timeoutIntervalForRequest = 30
        config.timeoutIntervalForResource = 60
        session = URLSession(configuration: config)
    }

    func request<T: Decodable>(
        path: String,
        method: HTTPMethod,
        body: Encodable? = nil,
        headers: [String: String]? = nil,
        completion: @escaping (Result<T, NetworkError>) -> Void
    ) {
        guard var url = URL(string: path, relativeTo: APIConfiguration.baseURL) else {
            completion(.failure(.invalidURL))
            return
        }

        if method == .get, let body = body {
            // For GET requests with parameters, append them as query items
            if let bodyDict = (try? JSONSerialization.jsonObject(with: JSONEncoder().encode(body))) as? [String: Any] {
                var urlComponents = URLComponents(url: url, resolvingAgainstBaseURL: true)
                urlComponents?.queryItems = bodyDict.map { URLQueryItem(name: $0.key, value: String(describing: $0.value)) }
                if let newUrl = urlComponents?.url {
                    url = newUrl
                }
            }
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method.rawValue
        request.addValue("application/json", forHTTPHeaderField: "Content-Type")
        request.addValue("application/json", forHTTPHeaderField: "Accept")

        // Add custom headers
        headers?.forEach { key, value in
            request.addValue(value, forHTTPHeaderField: key)
        }

        // Set request body for non-GET methods
        if let body = body, method != .get {
            do {
                request.httpBody = try JSONEncoder().encode(body)
            } catch {
                completion(.failure(.decodeFailed(error)))
                return
            }
        }

        let task = session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(.apiError(error.localizedDescription)))
                return
            }

            guard let httpResponse = response as? HTTPURLResponse else {
                completion(.failure(.unknown))
                return
            }

            guard let data = data else {
                completion(.failure(.noData))
                return
            }

            switch httpResponse.statusCode {
            case 200...299:
                do {
                    let decodedObject = try JSONDecoder().decode(T.self, from: data)
                    completion(.success(decodedObject))
                } catch {
                    completion(.failure(.decodeFailed(error)))
                }
            case 401:
                completion(.failure(.unauthorized))
            case 400...499:
                // Attempt to decode a general API error message if available
                if let apiError = try? JSONDecoder().decode(APIErrorMessage.self, from: data) {
                    completion(.failure(.apiError(apiError.message)))
                } else {
                    completion(.failure(.serverError(httpResponse.statusCode)))
                }
            case 500...599:
                completion(.failure(.serverError(httpResponse.statusCode)))
            default:
                completion(.failure(.unknown))
            }
        }
        task.resume()
    }
}

// MARK: - API Models

// Example User Model
struct User: Codable, Identifiable {
    let id: String
    let name: String
    let email: String
}

// Example Auth Request Body
struct LoginRequest: Encodable {
    let username: String
    let password: String
}

// Example Auth Response Body
struct AuthResponse: Decodable {
    let token: String
    let user: User
}

// Generic API Error Message
struct APIErrorMessage: Decodable {
    let message: String
}

// MARK: - API Endpoints and Usage

class UserAPI {
    private let networkService = NetworkService.shared
    private var authToken: String? // Store token after successful login

    func setAuthToken(_ token: String) {
        self.authToken = token
    }

    func clearAuthToken() {
        self.authToken = nil
    }

    // MARK: Authentication

    func login(credentials: LoginRequest, completion: @escaping (Result<AuthResponse, NetworkError>) -> Void) {
        networkService.request(
            path: "/auth/login", // Example path
            method: .post,
            body: credentials
        ) { [weak self] (result: Result<AuthResponse, NetworkError>) in
            if case .success(let authResponse) = result {
                self?.setAuthToken(authResponse.token)
            }
            completion(result)
        }
    }

    // MARK: User Data Retrieval

    func fetchCurrentUser(completion: @escaping (Result<User, NetworkError>) -> Void) {
        guard let token = authToken else {
            completion(.failure(.unauthorized))
            return
        }

        let headers = ["Authorization": "Bearer \(token)"]

        networkService.request(
            path: "/users/me", // Example path
            method: .get,
            headers: headers,
            completion: completion
        )
    }

    func fetchUser(by id: String, completion: @escaping (Result<User, NetworkError>) -> Void) {
        guard let token = authToken else {
            completion(.failure(.unauthorized))
            return
        }

        let headers = ["Authorization": "Bearer \(token)"]

        networkService.request(
            path: "/users/\(id)", // Example path
            method: .get,
            headers: headers,
            completion: completion
        )
    }

    // Example of a POST request with authentication for updating user data
    func updateUser(id: String, userData: User, completion: @escaping (Result<User, NetworkError>) -> Void) {
        guard let token = authToken else {
            completion(.failure(.unauthorized))
            return
        }

        let headers = ["Authorization": "Bearer \(token)"]

        networkService.request(
            path: "/users/\(id)",
            method: .post, // Assuming POST for update, could also be PUT
            body: userData,
            headers: headers,
            completion: completion
        )
    }
}


